// n8n Code node (JavaScript)
// Makes prompt safe to inject into a JSON string

const input = $json.prompt ?? "";

const jsonSafePrompt = input
  // escape backslashes FIRST
  .replace(/\\/g, "\\\\")

  // escape double quotes
  .replace(/"/g, '\\"')

  // remove line breaks
  .replace(/[\r\n]+/g, " ")

  // normalize smart quotes
  .replace(/[“”]/g, '\\"')
  .replace(/[‘’]/g, "'")

  // normalize long dashes
  .replace(/[–—]/g, "-")

  // collapse extra spaces
  .replace(/\s{2,}/g, " ")

  // trim
  .trim();

return [
  {
    json: {
      ...$json,
      prompt: jsonSafePrompt
    }
  }
];

